  console.error('FAIL: project.name or project.prefix missing or empty');
  process.exit(1);
}
if (typeof ctx.project.name !== 'string' || ctx.project.name.trim() === '') {
  console.error('FAIL: project.name is empty');
  process.exit(1);
}
if (typeof ctx.project.prefix !== 'string' || ctx.project.prefix.trim() === '') {
  console.error('FAIL: project.prefix is empty');
  process.exit(1);
}
// Check arrays are arrays
const arrayFields = ['entities', 'impactCategories', 'technicalDebt'];
for (const f of arrayFields) {
  if (ctx[f] && !Array.isArray(ctx[f])) {
    console.error('FAIL: ' + f + ' is not an array');
    process.exit(1);
  }
}
if (ctx.project.stack && !Array.isArray(ctx.project.stack)) {
  console.error('FAIL: project.stack is not an array');
